// ─── ScrollAndSwapText Component ────────────────────────────────────────────
const ScrollAndSwapText = ({ label, offset = ["0 0", "0 1"], className, containerRef, ...props }) => {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({
    container: containerRef,
    target: ref,
    offset: offset,
    layoutEffect: false,
  });
  const top = useTransform(scrollYProgress, [0, 1], ["0%", "-100%"]);
  const bottom = useTransform(scrollYProgress, [0, 1], ["100%", "0%"]);

  return (
    <span
      className={`flex overflow-hidden relative items-center justify-center ${className}`}
      ref={ref}
      {...props}
    >
      <span className="relative" style={{ color: "transparent" }} aria-hidden="true">{label}</span>
      <motion.span className="absolute" style={{ top }}>{label}</motion.span>
      <motion.span className="absolute" style={{ top: bottom }} aria-hidden="true">{label}</motion.span>
    </span>
  );
};

// ─── Typing Effect Hook ──────────────────────────────────────────────────────
function useTypingEffect(words, speed = 80, pause = 1800) {
  const [displayed, setDisplayed] = useState("");
  const [wordIdx, setWordIdx] = useState(0);
  const [charIdx, setCharIdx] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const current = words[wordIdx];
    let timeout;
    if (!deleting && charIdx < current.length) {
      timeout = setTimeout(() => setCharIdx(c => c + 1), speed);
    } else if (!deleting && charIdx === current.length) {
      timeout = setTimeout(() => setDeleting(true), pause);
    } else if (deleting && charIdx > 0) {
      timeout = setTimeout(() => setCharIdx(c => c - 1), speed / 2);
    } else if (deleting && charIdx === 0) {
      setDeleting(false);
      setWordIdx(i => (i + 1) % words.length);
    }
    setDisplayed(current.slice(0, charIdx));
    return () => clearTimeout(timeout);
  }, [charIdx, deleting, wordIdx, words, speed, pause]);

  return displayed;
}

