function DisplayCard({ icon, title, description, date }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        position: "relative", display: "flex", height: 136, width: 340,
        userSelect: "none", flexDirection: "column", justifyContent: "space-between",
        borderRadius: 12, border: hovered ? "2px solid #0000CD" : "2px solid #d0cec6",
        background: hovered ? "#EDEBE3" : "rgba(237,235,227,0.85)",
        backdropFilter: "blur(8px)", padding: "14px 18px",
        transition: "all 0.5s", boxSizing: "border-box",
        filter: hovered ? "grayscale(0%)" : "grayscale(30%)",
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <span style={{ display: "inline-flex", borderRadius: "50%", background: "#0000CD", padding: 5 }}>
          {icon}
        </span>
        <p style={{ fontSize: 17, fontWeight: 700, color: "#0000CD", margin: 0, letterSpacing: "-0.01em" }}>{title}</p>
      </div>
      <p style={{ fontSize: 15, margin: 0, color: "#1a1a1a", fontWeight: 500 }}>{description}</p>
      <p style={{ fontSize: 12, color: "#9e9b93", margin: 0, letterSpacing: "0.05em", textTransform: "uppercase" }}>{date}</p>
    </div>
  );
}

