// ─── Contact ─────────────────────────────────────────────────────────────────
function Contact() {
  const [sent, setSent] = useState(false);
  const [sending, setSending] = useState(false);
  const [error, setError] = useState("");
  const [form, setForm] = useState({ name: "", email: "", message: "" });

  const handleSubmit = async () => {
    if (!form.name || !form.email || !form.message) return;
    setSending(true);
    setError("");
    try {
      await window.emailjs.send(
        "service_wilj558",
        "template_9truhtn",
        {
          name: form.name,
          from_name: form.name,
          email: form.email,
          from_email: form.email,
          reply_to: form.email,
          message: form.message,
        },
        "Ulic8uKlCkbbu8nLA"
      );
      setSent(true);
    } catch (err) {
      console.error("EmailJS error:", err);
      setError("Error: " + (err?.text || err?.message || JSON.stringify(err)));
    } finally {
      setSending(false);
    }
  };

  return (
    <section id="contact" style={{ width: "100vw", boxSizing: "border-box", padding: "8rem 0" }}>
      <div className="contact-grid" style={{  padding: "0 clamp(1.5rem, 5vw, 5rem)", display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8rem" }}>
        <motion.div initial={{ opacity: 0, x: -40 }} whileInView={{ opacity: 1, x: 0 }} viewport={{ once: true }} transition={{ duration: 0.8 }}>
          <h2 style={{
            fontFamily: "'Helvetica Neue', Helvetica, Arial, sans-serif",
            fontWeight: 900, fontSize: "clamp(48px, 6vw, 88px)",
            letterSpacing: "-0.04em", lineHeight: 0.9, color: "#1a1a1a", marginBottom: "3rem"
          }}>let's<br /><span style={{ color: "#0000CD" }}>connect.</span></h2>

          <p style={{ fontSize: 16, lineHeight: 1.8, color: "#666", marginBottom: "3rem", maxWidth: 400 }}>
            Open to internships, collaborations, and interesting conversations about technology, design, or life.
          </p>

          <div style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}>
            {[
              { label: "Email", value: "saishbhujbal03@gmail.com", href: "mailto:saishbhujbal03@gmail.com" },
              { label: "GitHub", value: "github.com/Saish-3", href: "https://github.com/Saish-3" },
              { label: "LinkedIn", value: "linkedin.com/in/saish-bhujbal", href: "https://www.linkedin.com/in/saish-bhujbal-99a56b301/" },
            ].map(link => (
              <div key={link.label} style={{ borderBottom: "1px solid #d0cec6", paddingBottom: "1.5rem" }}>
                <div style={{ fontSize: 11, letterSpacing: "0.15em", textTransform: "uppercase", color: "#9e9b93", marginBottom: "0.4rem" }}>{link.label}</div>
                <a href={link.href} target="_blank" rel="noopener noreferrer" style={{ fontWeight: 700, fontSize: 16, color: "#1a1a1a", textDecoration: "none", transition: "color 0.2s" }}
                  onMouseEnter={e => e.target.style.color = "#0000CD"}
                  onMouseLeave={e => e.target.style.color = "#1a1a1a"}>{link.value} ↗</a>
              </div>
            ))}
          </div>
        </motion.div>

        {/* Contact form */}
        <motion.div initial={{ opacity: 0, x: 40 }} whileInView={{ opacity: 1, x: 0 }} viewport={{ once: true }} transition={{ duration: 0.8, delay: 0.2 }}>
          <AnimatePresence mode="wait">
            {sent ? (
              <motion.div key="sent" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} style={{ height: "100%", display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", textAlign: "center" }}>
                <div style={{ width: 64, height: 64, borderRadius: "50%", background: "#0000CD", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: "1.5rem" }}>
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5"><polyline points="20 6 9 17 4 12"/></svg>
                </div>
                <h3 style={{ fontWeight: 900, fontSize: 32, letterSpacing: "-0.03em", color: "#1a1a1a", marginBottom: "1rem" }}>Message Sent!</h3>
                <p style={{ fontSize: 16, color: "#666" }}>I'll get back to you soon.</p>
                <button onClick={() => { setSent(false); setForm({ name: "", email: "", message: "" }); }}
                  style={{ marginTop: "2rem", background: "none", border: "2px solid #1a1a1a", padding: "12px 28px", fontWeight: 700, fontSize: 12, letterSpacing: "0.1em", textTransform: "uppercase", cursor: "pointer", transition: "all 0.2s" }}>
                  Send Another
                </button>
              </motion.div>
            ) : (
              <motion.div key="form">
                {["name", "email", "message"].map(field => (
                  <div key={field} style={{ marginBottom: "2rem" }}>
                    <label style={{ display: "block", fontSize: 11, letterSpacing: "0.15em", textTransform: "uppercase", color: "#9e9b93", marginBottom: "0.75rem", fontWeight: 600 }}>{field}</label>
                    {field === "message" ? (
                      <textarea rows={5} value={form[field]}
                        onChange={e => setForm(f => ({ ...f, [field]: e.target.value }))}
                        style={{ width: "100%", background: "transparent", border: "none", borderBottom: "2px solid #d0cec6", padding: "0.75rem 0", fontSize: 16, color: "#1a1a1a", outline: "none", resize: "none", fontFamily: "inherit", transition: "border-color 0.2s" }}
                        onFocus={e => e.target.style.borderColor = "#0000CD"}
                        onBlur={e => e.target.style.borderColor = "#d0cec6"}
                        placeholder={`Your ${field}...`} />
                    ) : (
                      <input type={field === "email" ? "email" : "text"} value={form[field]}
                        onChange={e => setForm(f => ({ ...f, [field]: e.target.value }))}
                        style={{ width: "100%", background: "transparent", border: "none", borderBottom: "2px solid #d0cec6", padding: "0.75rem 0", fontSize: 16, color: "#1a1a1a", outline: "none", fontFamily: "inherit", transition: "border-color 0.2s" }}
                        onFocus={e => e.target.style.borderColor = "#0000CD"}
                        onBlur={e => e.target.style.borderColor = "#d0cec6"}
                        placeholder={field === "name" ? "John Doe" : "john@example.com"} />
                    )}
                  </div>
                ))}
                <button onClick={handleSubmit} disabled={sending}
                  style={{
                    background: sending ? "#6666cc" : "#0000CD", color: "#fff", padding: "16px 40px",
                    fontWeight: 800, fontSize: 13, letterSpacing: "0.12em", textTransform: "uppercase",
                    border: "none", cursor: sending ? "not-allowed" : "pointer", transition: "background 0.2s", width: "100%"
                  }}
                  onMouseEnter={e => { if (!sending) e.target.style.background = "#0000a8"; }}
                  onMouseLeave={e => { if (!sending) e.target.style.background = "#0000CD"; }}>
                  {sending ? "Sending..." : "Send Message →"}
                </button>
                {error && <p style={{ marginTop: "1rem", fontSize: 13, color: "#cc0000" }}>{error}</p>}
              </motion.div>
            )}
          </AnimatePresence>
        </motion.div>
      </div>
    </section>
  );
}

